// collapse.js — click-to-collapse for Pandoc --section-divs output
(function () {
  'use strict';

  function init() {
    // Target sections generated by Pandoc --section-divs
    var sections = document.querySelectorAll('.post-content section');

    sections.forEach(function (sec) {
      var heading = sec.querySelector(':scope > h1, :scope > h2, :scope > h3, :scope > h4');
      if (!heading) return;

      heading.style.cursor = 'pointer';
      heading.addEventListener('click', function (e) {
        if (e.target.tagName === 'A') return; // don't toggle on link clicks
        sec.classList.toggle('collapsed');
      });
    });

    function uncollapseTarget() {
      var hash = window.location.hash;
      if (!hash) return;
      try {
        var target = document.querySelector(hash);
      } catch (e) {
        return; // invalid selector
      }
      if (!target) return;
      // Uncollapse ancestor sections
      var el = target.closest('section');
      while (el) {
        el.classList.remove('collapsed');
        el = el.parentElement ? el.parentElement.closest('section') : null;
      }
      // If the target itself is a section, uncollapse it too
      if (target.tagName === 'SECTION') {
        target.classList.remove('collapsed');
      }
    }

    uncollapseTarget();
    window.addEventListener('hashchange', uncollapseTarget);
  }

  // Run init after DOM is ready.
  // If MathJax has fully loaded (startup.promise exists), wait for it
  // to finish typesetting so it doesn't rewrite elements after we bind.
  // Note: the template sets a MathJax config object in <head>, so
  // window.MathJax may exist before the library loads — check .startup.
  function ready(fn) {
    if (document.readyState !== 'loading') {
      fn();
    } else {
      document.addEventListener('DOMContentLoaded', fn);
    }
  }

  ready(function () {
    if (window.MathJax && MathJax.startup && MathJax.startup.promise) {
      MathJax.startup.promise.then(init);
    } else {
      init();
    }
  });
})();
